module top_module(

               topsig,

               reset_clk
               );input  reset_clk;
   output topsig;



   reg    topsig;
`define TOPSIG  {topsig}

   always @ (posedge reset_clk) begin
      `TOPSIG <= #0 1'b1;
   end

   task direct_write;
      input val;
      begin
         `TOPSIG = val;
      end
   endtask
endmodule
